mapper.select:
/* 팀목록 조회 TeamDAO.list */
SELECT ROW_NUMBER() OVER(ORDER BY TEAM.TEAM_ID ASC) AS lineNo , TEAM.TEAM_ID , TEAM.TEAM_TYCD , TEAM.TEAMNM , TEAM.RGTR_ID , TEAM.REG_DTTM , TEAM.MDFR_ID , TEAM.MOD_DTTM , NVL((SELECT USR.USERNM FROM TB_LMS_USER USR JOIN TB_LMS_TEAM_MBR TEAM_MBR ON USR.USER_ID = TEAM_MBR.USER_ID WHERE TEAM_MBR.LDRYN = 'Y' AND TEAM_MBR.TEAM_ID = TEAM.TEAM_ID), '-') AS leaderNm , (SELECT COUNT(tlts.USER_ID) FROM TB_LMS_TEAM_MBR tlts WHERE tlts.TEAM_ID = TEAM.TEAM_ID) AS teamMbrCnt FROM TB_LMS_TEAM TEAM
AND TEAM.TEAM_ID = #{teamCd}
AND TEAM.LRN_GRP_ID = #{teamCtgrCd}
AND LOWER(TEAM.TEAMNM) LIKE LOWER(CONCAT('%', #{teamNm}, '%'))
ORDER BY TEAM.TEAM_ID ASC

/* 팀토론 토론방 팀리스트 TeamDAO.teamList */ SELECT ROW_NUMBER() OVER(ORDER BY TEAM_ID ASC) as lineNo , TEAM_TYCD as teamCtgrCd , TEAM_ID as teamCd , TEAMNM as teamNm , IFNULL((SELECT U.USERNM FROM TB_LMS_USR U, TB_LMS_ATNDLC_SBJCT S, TB_LMS_TEAM_MBR M WHERE U.USER_ID = S.USER_ID AND S.STD_ID = M.STD_ID AND M.TEAM_ID = A.TEAM_ID and M.TEAM_LDRYN = 'Y'),'-') as leaderNm , (select COUNT(tlts.STD_ID) from TB_LMS_TEAM_MBR tlts where tlts.TEAM_ID = A.TEAM_ID) as teamMbrCnt FROM TB_LMS_TEAM A WHERE 1=1
AND TEAM_TYCD = #{teamCtgrCd}
ORDER BY TEAM_ID ASC

mapper.insert:
/*
	팀 등록
	TeamDAO.insert
*/
INSERT INTO TB_LMS_TEAM (
	TEAM_TYCD
	, TEAM_ID
	, TEAMNM
	, RGTR_ID
	, FRST_INQ_DTTM
) VALUES (
	#{teamCtgrCd}
	, #{teamCd}
	, #{teamNm}
	, #{rgtrId}
	, FN_DTTM()
)

mapper.update:
/*
	팀 수정
	TeamDAO.update
*/
UPDATE TB_LMS_TEAM SET
	TEAMNM = #{teamNm}
 WHERE TEAM_ID = #{teamCd}

mapper.select:
/* 팀 정보 조회 TeamDAO.select */
SELECT A.TEAM_ID , A.TEAMNM , A.TEAM_TYCD , (SELECT COUNT(TLTS.STD_ID) FROM TB_LMS_TEAM_MBR TLTS WHERE TLTS.TEAM_ID = A.TEAM_ID) AS TEAM_MBR_CNT FROM TB_LMS_TEAM A WHERE 1 = 1
AND A.TEAM_ID = #{teamCd}

mapper.delete:
/*
	팀원 삭제
	TeamDAO.deleteStd
*/
DELETE FROM TB_LMS_TEAM_MBR
WHERE TEAM_ID = #{teamCd}

/*
	팀 삭제
	TeamDAO.delete
*/
DELETE FROM TB_LMS_TEAM
WHERE TEAM_ID = #{teamCd}

mapper.select:
/* 팀 정보의 전체 카운트 TeamDAO.count */ SELECT COUNT(*) FROM ( SELECT ROW_NUMBER() OVER(ORDER BY TEAM_ID DESC) AS LINE_NO , TEAM_TYCD , TEAM_ID , TEAMNM FROM TB_LMS_TEAM A WHERE 1=1
AND TEAM_TYCD = #{teamCtgrCd}
ORDER BY TEAM_ID DESC ) T

/*
	팀원 조회
	TeamDAO.selectTeamCtgrStd
*/
SELECT NVL(LISTAGG(TLTS.STD_ID,',') WITHIN GROUP(ORDER BY TLTS.STD_ID),' ') AS STD_ID
FROM TB_LMS_TEAM_MBR TLTS
JOIN TB_LMS_TEAM TLT ON TLTS.TEAM_ID = TLT.TEAM_ID
WHERE TLT.TEAM_TYCD = #{teamCtgrCd}

	AND TLT.TEAM_ID != #{teamCd}

/* 팀원 리스트 조회 TeamDAO.selectTeamMemberList */ SELECT ROW_NUMBER() OVER(ORDER BY ROLE DESC, B.USERNM) AS LINE_NO , TEAM_ID AS teamCd
, B.DEPTNM , A.USER_ID
, B.USERNM , ROLE , TEAM_LDRYN , NVL((SELECT SCYR FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = A.STD_ID), '-') AS SCYR , NVL(B.ENTR_YY ,'-') AS ENTR_YY , NVL(B.ENTR_HY, '-') AS ENTR_HY , NVL(B.ENTR_GBN_NM, '-') AS ENTR_GBN_NM FROM TB_LMS_TEAM_MBR A LEFT JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID WHERE 1=1 AND TEAM_ID = #{teamCd} ORDER BY LINE_NO
